def _project_name(data: dict) -> str:
    """Derive a short project folder name from the hook payload's cwd field."""
    cwd = data.get("cwd", "")
    if not cwd:
        return "_unknown"
    # Use the last directory component as the project name
    name = Path(cwd).name or "_root"
    # Sanitize: keep only safe chars
    safe = "".join(c if (c.isalnum() or c in "-_.") else "_" for c in name)
    return safe or "_unknown"


